 */
public class HessianService {

    // Default whitelist containing common Java types to ensure basic functionality out of the box
    private static final Set<String> DEFAULT_WHITELIST = new HashSet<>(Arrays.asList(
            "java.lang.String",
            "java.lang.Integer",
            "java.lang.Long",
            "java.lang.Double",
            "java.lang.Float",
            "java.lang.Boolean",
            "java.lang.Byte",
            "java.lang.Short",
            "java.lang.Character",
