            "java.util.ArrayList",
            "java.util.HashMap",
            "java.util.LinkedHashMap",
            "java.util.HashSet",
            "java.util.LinkedHashSet",
            "[B", // byte[]
            "[Ljava.lang.Object;",
            "[Ljava.lang.String;"
    ));

