        this.serializerFactory = createSecureFactory(DEFAULT_WHITELIST);
    }

    /**
     * Constructor allowing custom configuration of the allowed class whitelist.
     *
     * @param customWhitelist Set of fully qualified class names allowed for deserialization
     */
    public HessianService(Set<String> customWhitelist) {
        this.serializerFactory = createSecureFactory(customWhitelist);
    }

    /**
     * Creates a SerializerFactory that enforces a class whitelist.
     */
    private SerializerFactory createSecureFactory(Set<String> whitelist) {
        return new SerializerFactory() {
            @Override
            public Deserializer getObjectDeserializer(String className) {
                if (!isClassAllowed(className, whitelist)) {
                    throw new HessianProtocolException("Unauthorized deserialization attempt for class: " + className);
                }
                return super.getObjectDeserializer(className);
            }
        };
    }

    /**
     * Checks if a class name is allowed for deserialization.
     * Handles array types by checking the component type.
     */
    private boolean isClassAllowed(String className, Set<String> whitelist) {
        if (whitelist.contains(className)) {
            return true;
        }

        // Handle array types (e.g., "[Ljava.lang.String;" or "[B")
        if (className != null && className.startsWith("[")) {
            // Strip array prefixes and the trailing semicolon for object arrays
            String componentType = className.replaceFirst("^\\[+", "");
            if (componentType.endsWith(";")) {
                componentType = componentType.substring(0, componentType.length() - 1);
                if (componentType.startsWith("L")) {
                    componentType = componentType.substring(1);
                }
            }
            return whitelist.contains(componentType);
        }

        return false;
    }

    /**
     * Deserializes user data.
     * Accepts a byte array provided by the user and performs deserialization using Hessian2Input.
     *
     * @param serializedData The serialized byte array data
     * @return The deserialized object
     * @throws IOException Thrown when an IO exception occurs during deserialization
     * @throws IllegalArgumentException Thrown when input data is invalid
     */
    public Object deserializeUserData(byte[] serializedData) throws IOException {
        if (serializedData == null || serializedData.length == 0) {
            throw new IllegalArgumentException("Serialized data cannot be empty");
        }

        // Use try-with-resources to ensure streams are closed automatically
        try (ByteArrayInputStream bis = new ByteArrayInputStream(serializedData)) {
            Hessian2Input hessianInput = new Hessian2Input(bis);

            // Apply the secure serializer factory
            hessianInput.setSerializerFactory(serializerFactory);

            // Perform deserialization
            return hessianInput.readObject();
        } catch (HessianProtocolException e) {
            throw new IOException("Hessian protocol error (possibly security violation): " + e.getMessage(), e);
        } catch (IOException e) {
            throw new IOException("Deserialization failed: " + e.getMessage(), e);
        }
    }
}

